# Shapes module with interfaces and abstract classes
from utils import ShapeCategory, format_measurement

interface IDrawable:
    def draw() -> str

interface IMeasurable:
    def get_area() -> float
    def get_perimeter() -> float

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def describe(self) -> str

    @virtual
    def display(self) -> str:
        return "Shape: " + self.name

class Polygon(Shape):
    sides: list[float]

    def __init__(self, name: str, sides: list[float]):
        super().__init__(name)
        self.sides = sides

    @override
    def describe(self) -> str:
        return "Polygon with " + str(len(self.sides)) + " sides"

    def get_perimeter(self) -> float:
        total: float = 0.0
        for side in self.sides:
            total = total + side
        return total

class Triangle(Polygon, IDrawable, IMeasurable):
    base: float
    height: float

    def __init__(self, base: float, height: float, side_a: float, side_b: float, side_c: float):
        sides: list[float] = [base, side_a, side_b, side_c]
        super().__init__("Triangle", sides)
        self.base = base
        self.height = height

    @override
    def describe(self) -> str:
        return "Triangle with base " + str(self.base)

    @override
    def display(self) -> str:
        return self.describe()

    def get_area(self) -> float:
        return 0.5 * self.base * self.height

    def draw(self) -> str:
        return "Drawing triangle"

    def get_perimeter(self) -> float:
        return super().get_perimeter()

class Square(Polygon, IDrawable, IMeasurable):
    side: float

    def __init__(self, side: float):
        sides: list[float] = [side, side, side, side]
        super().__init__("Square", sides)
        self.side = side

    @override
    def describe(self) -> str:
        return "Square with side " + str(self.side)

    def get_area(self) -> float:
        return self.side * self.side

    def draw(self) -> str:
        return "Drawing square"
